// --- AUDIO ENGINE GLOBALS ---
int audioSamplesRemaining = 0;
int audioCurrentFreq = 0;
int audioWaveCounter = 0;
int audioCurrentAmplitude = 0;
int audioPhase = 0;

void triggerSuccessSound()
{
  audioSamplesRemaining = 8000 / 10;
  audioCurrentFreq = 2093;
  audioWaveCounter = 0;
  audioCurrentAmplitude = 0x00FFFFFF;
  audioPhase = 1;
}

void triggerFailSound()
{
  audioSamplesRemaining = 8000 / 3;
  audioCurrentFreq = 150;
  audioWaveCounter = 0;
  audioCurrentAmplitude = 0x00FFFFFF;
  audioPhase = 0;
}

void updateAudio()
{
  if (audioSamplesRemaining <= 0)
  {
    if (audioPhase == 1)
    {
      audioSamplesRemaining = 8000 / 20;
      audioCurrentFreq = 0;
      audioPhase = 2;
    }
    else if (audioPhase == 2)
    {
      audioSamplesRemaining = (8000 * 15) / 100;
      audioCurrentFreq = 2637;
      audioCurrentAmplitude = 0x00FFFFFF;
      audioWaveCounter = 0;
      audioPhase = 3;
    }
    else
    {
      return;
    }
  }

  volatile int *audioPtr = (int *)AUDIO_BASE;
  int fifoSpace = *(audioPtr + 1);
  int leftSpace = (fifoSpace >> 24) & 0xFF;
  int rightSpace = (fifoSpace >> 16) & 0xFF;

  int spaceToWrite = (leftSpace < rightSpace) ? leftSpace : rightSpace;
  if (spaceToWrite > audioSamplesRemaining)
    spaceToWrite = audioSamplesRemaining;

  for (int i = 0; i < spaceToWrite; i++)
  {
    if (audioCurrentFreq == 0)
    {
      *(audioPtr + 2) = 0;
      *(audioPtr + 3) = 0;
    }
    else
    {
      *(audioPtr + 2) = audioCurrentAmplitude;
      *(audioPtr + 3) = audioCurrentAmplitude;

      audioWaveCounter++;
      int halfPeriod = 8000 / audioCurrentFreq / 2;
      if (audioWaveCounter >= halfPeriod)
      {
        audioCurrentAmplitude = -audioCurrentAmplitude;
        audioWaveCounter = 0;
      }
    }
    audioSamplesRemaining--;
  }
}

int main(void)
{
  volatile int *pixel_ctrl_ptr = (int *)0xFF203020;

  *(pixel_ctrl_ptr + 1) = (int)&buffer1;
  wait_for_vsync();

  pixel_buffer_start = *pixel_ctrl_ptr;
  clearScreen();

  *(pixel_ctrl_ptr + 1) = (int)&buffer2;
  pixel_buffer_start = *(pixel_ctrl_ptr + 1);
  clearScreen();
  clearCharacter();

  set_itimer();
  enable_interrupts();

  unsigned int counter = 0;

  updateLEDs(0);

  while (1)
  {
    if (state == MENU_STATE)
    {
      clearScreen();
      drawMenu();
      timerStarted = 0;
      counter++;

      char keyByte;
      while (readPS2(&keyByte))
      {
        if (keyByte == (char)0xE0)
        {
          extendedKey = true;
        }
        else if (keyByte == (char)0xF0)
        {
          ignoreNext = true;
        }
        else if (ignoreNext)
        {
          ignoreNext = false;
          extendedKey = false;
        }
        else
        {
          bool isUp   = (!extendedKey && keyByte == (char)0x1D) ||
                        (extendedKey  && keyByte == (char)0x75);
          bool isDown = (!extendedKey && keyByte == (char)0x1B) ||
                        (extendedKey  && keyByte == (char)0x72);

          extendedKey = false;

          if (isUp)
          {
            if (menuSelection > 0) menuSelection--;
          }
          else if (isDown)
          {
            if (menuSelection < 2) menuSelection++;
          }
          else if (keyByte == (char)0x5A)
          {
            gameDifficulty = menuSelection;
            clearCharacter();
            srand(counter);

            for (int i = 0; i < NUM_PINS; i++)
            {
              int randomPin;
              bool isDuplicate;
              do {
                randomPin = rand() % NUM_PINS;
                isDuplicate = false;
                for (int j = 0; j < i; j++)
                {
                  if (pinSequence[j] == randomPin) { isDuplicate = true; break; }
                }
              } while (isDuplicate);

              pinSequence[i]    = randomPin;
              pinYPositions[i]  = PIN_REST_Y;
              pinSet[i]         = false;
              pinTargetY[i]     = 70 + (rand() % 31);
            }

            currentSequenceIndex = 0;
            matchedPins = 0;

            playStartSound();

            elapsedTime  = 0;
            timerStarted = 1;

            do {
              rotary_counter = rand() % 256;
            } while (rotary_counter >= target_rotary_start - 30 &&
                     rotary_counter <= target_rotary_end + 30);

            // Draw static lock to both buffers once
            pixel_buffer_start = (int)&buffer1;
            drawStaticLock();

            pixel_buffer_start = (int)&buffer2;
            drawStaticLock();

            state = GAME_STATE;
          }
        }
      }
    }
    else if (state == GAME_STATE)
    {
      char keyByte;
      while (readPS2(&keyByte))
      {
        if (keyByte == (char)0xE0)
        {
          extendedKey = true;
        }
        else if (keyByte == (char)0xF0)
        {
          ignoreNext = true;
        }
        else if (ignoreNext)
        {
          ignoreNext = false;
          extendedKey = false;

          if (keyByte == (char)0x1D || keyByte == (char)0x75)
          {
            isHoldingW = false;
            int margin = 3;
            if (gameDifficulty == DIFF_MEDIUM) margin = 2;
            else if (gameDifficulty == DIFF_HARD) margin = 1;

            if (!pinSet[currentPinIndex])
            {
              if (pinYPositions[currentPinIndex] >= pinTargetY[currentPinIndex] - margin &&
                  pinYPositions[currentPinIndex] <= pinTargetY[currentPinIndex] + margin)
              {
                if (currentPinIndex == pinSequence[currentSequenceIndex])
                {
                  pinSet[currentPinIndex] = true;
                  currentSequenceIndex++;
                  triggerSuccessSound();
                }
                else
                {
                  for (int i = 0; i < NUM_PINS; i++) pinSet[i] = false;
                  currentSequenceIndex = 0;
                  triggerFailSound();
                }
              }
            }
          }
        }
        else
        {
          bool isLeft  = (!extendedKey && keyByte == (char)0x1C) ||
                         (extendedKey  && keyByte == (char)0x6B);
          bool isRight = (!extendedKey && keyByte == (char)0x23) ||
                         (extendedKey  && keyByte == (char)0x74);
          bool isUp    = (!extendedKey && keyByte == (char)0x1D) ||
                         (extendedKey  && keyByte == (char)0x75);

          extendedKey = false;

          if (isLeft && !isHoldingW)
          {
            if (currentPinIndex > 0) currentPinIndex--;
          }
          else if (isRight && !isHoldingW)
          {
            if (currentPinIndex < NUM_PINS - 1) currentPinIndex++;
          }
          else if (isUp)
          {
            if (!pinSet[currentPinIndex] && rotary_in_range)
              isHoldingW = true;
          }
          else if (keyByte == (char)0x21)
          { // C = clockwise
            rotary_counter++;
            if (rotary_counter > 255) rotary_counter = 0;
            *LEDR_ptr = rotary_counter;
          }
          else if (keyByte == (char)0x22)
          { // X = counter-clockwise
            rotary_counter--;
            if (rotary_counter < 0) rotary_counter = 255;
            *LEDR_ptr = rotary_counter;
          }
        }
      }

      // Game physics
      if (isHoldingW)
      {
        if (rotary_in_range)
        {
          pinYPositions[currentPinIndex] -= 1;
          if (pinYPositions[currentPinIndex] < 65)
            pinYPositions[currentPinIndex] = 65;
        }
        else
        {
          isHoldingW = false; // drop pin if rotary leaves range
        }
      }
      else
      {
        for (int i = 0; i < NUM_PINS; i++)
        {
          if (!pinSet[i] && pinYPositions[i] < PIN_REST_Y)
          {
            pinYPositions[i] += 4;
            if (pinYPositions[i] > PIN_REST_Y) pinYPositions[i] = PIN_REST_Y;
          }
        }
      }

      eraseDynamicElements();
      pickXPosition = LOCK_BASE_X + 32 + (currentPinIndex * 32);
      drawDynamicElements();

      int maxTime = 180;
      if (gameDifficulty == DIFF_MEDIUM) maxTime = 120;
      if (gameDifficulty == DIFF_HARD)   maxTime = 60;

      int setTotal = 0;
      for (int i = 0; i < NUM_PINS; i++)
        if (pinSet[i]) setTotal++;

      if (setTotal == NUM_PINS)
      {
        timerStarted = 0;
        gameWon = true;
        clearCharacter();
        state = END_STATE;
      }
      else if (elapsedTime >= maxTime)
      {
        timerStarted = 0;
        gameWon = false;
        clearCharacter();
        state = END_STATE;
      }
      else
      {
        drawTimer();
        drawRotaryBar(); // includes TENSION label, padlock icons, control hint
      }
    }
    else if (state == END_STATE)
    {
      clearScreen();
      drawEndScreen();

      char keyByte;
      while (readPS2(&keyByte))
      {
        if (keyByte == (char)0xF0)
        {
          ignoreNext = true;
        }
        else if (ignoreNext)
        {
          ignoreNext = false;
        }
        else if (keyByte == 0x5A)
        {
          clearCharacter();
          state = MENU_STATE;
        }
      }
    }

    updateAudio();
    wait_for_vsync();
    pixel_buffer_start = *(pixel_ctrl_ptr + 1);
  }
}

// ============================================================
// drawMenu
// ============================================================
void drawMenu()
{
  drawRectangle(80, 40, 160, 160, 0x001F);
  writeString(30, 15, "WELCOME TO LOCK PICK");

  int baseY   = 90;
  int boxHeight = 24;
  int spacing = 35;

  for (int i = 0; i < 3; i++)
  {
    short int boxColor = (i == menuSelection) ? 0x07E0 : 0x001F;
    drawRectangle(100, baseY + (i * spacing), 120, boxHeight, boxColor);
  }

  writeString(38, 24, "EASY");
  writeString(37, 33, "MEDIUM");
  writeString(38, 41, "HARD");
}

// ============================================================
// drawEndScreen
// ============================================================
void drawEndScreen()
{
  drawRectangle(0, 0, 320, 240, COLOR_BLACK);

  if (gameWon)
  {
    drawRectangle(60, 80, 200, 80, COLOR_GOLD);
    writeString(34, 23, "LOCK PICKED!");
    char timeMsg[30];
    snprintf(timeMsg, sizeof(timeMsg), "FINAL TIME: %03d SEC", elapsedTime);
    writeString(30, 26, timeMsg);
  }
  else
  {
    drawRectangle(60, 80, 200, 80, 0xF800);
    writeString(35, 23, "TIME'S UP!");
    writeString(31, 26, "YOU FAILED TO PICK THE LOCK");
  }

  writeString(29, 32, "PRESS ENTER TO RESTART");
}

// ============================================================
// clearScreen
// ============================================================
void clearScreen()
{
  for (int i = 0; i < 320; i++)
    for (int j = 0; j < 240; j++)
      plot_pixel(i, j, 0x0000);
}

// ============================================================
// drawTimer  --  also draws "PIN: X 5" at top-right
// ============================================================
void drawTimer()
{
  char timeStr[20];
  snprintf(timeStr, sizeof(timeStr), "TIME: %03d", elapsedTime);
  writeString(2, 2, timeStr);   // top-left

  // "PIN: current+1 / NUM_PINS" at top-right
  char pinStr[20];
  snprintf(pinStr, sizeof(pinStr), "PIN: %d %d", currentPinIndex + 1, NUM_PINS);
  writeString(68, 2, pinStr);
}

// ============================================================
// writeCharacter / writeString
// ============================================================
void writeCharacter(int x, int y, char c)
{
  volatile char *character_buffer = (char *)(CHAR_BUFFER_BASE + (y << 7) + x);
  *character_buffer = c;
}

void writeString(int x, int y, char *str)
{
  int i = 0;
  while (str[i] != '\0')
  {
    writeCharacter(x + i, y, str[i]);
    i++;
  }
}

// ============================================================
// drawRectangle / plot_pixel / clearCharacter
// ============================================================
void drawRectangle(int x0, int y0, int width, int height, short int color)
{
  for (int x = x0; x < x0 + width; x++)
    for (int y = y0; y < y0 + height; y++)
      plot_pixel(x, y, color);
}

void plot_pixel(int x, int y, short int line_color)
{
  volatile short int *one_pixel_address;
  one_pixel_address = pixel_buffer_start + (y << 10) + (x << 1);
  *one_pixel_address = line_color;
}

void clearCharacter()
{
  for (int x = 0; x < 80; x++)
    for (int y = 0; y < 60; y++)
      writeCharacter(x, y, ' ');
}

// ============================================================
// drawSpring  --  draws a coiled spring at the top of a chamber
//   chamberX = left edge of the chamber (same as 'cx' in loops)
// ============================================================
void drawSpring(int chamberX)
{
  // 6 alternating stripes: silver / dark-gray
  for (int s = 0; s < 6; s++)
  {
    short int col = (s % 2 == 0) ? COLOR_SPRING : 0x4208; // silver / charcoal
    drawRectangle(chamberX + 2, LOCK_BASE_Y + 2 + (s * 3),
                  CHAMBER_WIDTH - 4, 2, col);
  }
}

