// ============================================================
// drawDynamicElements  --  pins, lockpick, springs (redrawn after erase)
// ============================================================
void drawDynamicElements()
{
  int lineThickness = 3;
  int marginOffset  = 3;
  if (gameDifficulty == DIFF_MEDIUM) { lineThickness = 2; marginOffset = 2; }
  else if (gameDifficulty == DIFF_HARD) { lineThickness = 1; marginOffset = 1; }

  for (int i = 0; i < NUM_PINS; i++)
  {
    int pinX    = LOCK_BASE_X + 25 + (i * 32);
    int currentY = pinYPositions[i];
    int targetY  = pinTargetY[i];

    // Redraw spring coil (erased by eraseDynamicElements)
    drawSpring(pinX);

    if (pinSet[i])
    {
      // ----- PIN IS LOCKED IN (SET) -----
      // Shear line turns GREEN to show this pin is picked
      drawRectangle(pinX, targetY - marginOffset, CHAMBER_WIDTH, lineThickness, COLOR_GREEN);

      int pinSectionHeight = 20;

      // Driver pin: sits above the green shear line
      int topPinBottomEdge = targetY - marginOffset;
      drawRectangle(pinX + 2, topPinBottomEdge - pinSectionHeight,
                    CHAMBER_WIDTH - 4, pinSectionHeight, COLOR_GOLD);

      // Key pin: sits below the shear line
      int bottomPinTopEdge = topPinBottomEdge + lineThickness;
      drawRectangle(pinX + 2, bottomPinTopEdge,
                    CHAMBER_WIDTH - 4, pinSectionHeight, COLOR_GOLD);
    }
    else
    {
      // ----- PIN IS UNPICKED -----
      // Red shear line remains
      drawRectangle(pinX, targetY - marginOffset, CHAMBER_WIDTH, lineThickness, COLOR_RED);

    //   // Highlight the active pin chamber with a faint gold border
    //   if (i == currentPinIndex)
    //     drawRectangle(pinX - 1, LOCK_BASE_Y + 20, 1, 68, COLOR_GOLD);

      // Driver pin (top half — above keyway gap)
      drawRectangle(pinX + 2, currentY - 22, CHAMBER_WIDTH - 4, 20, COLOR_GOLD);

      // Key pin (bottom half — below keyway gap)
      drawRectangle(pinX + 2, currentY,      CHAMBER_WIDTH - 4, 20, COLOR_GOLD);
     }
  }

  // ---- LOCKPICK ----
  // Horizontal bar: from left edge to current pin column
  drawRectangle(0, 142, pickXPosition, 4, COLOR_PICK);

  // Vertical tip pointing up toward the active pin
  int tipTopY = 136; // resting position (just above keyway)
  if (isHoldingW)
  {
    // Tip follows the key-pin's bottom edge when being lifted
    tipTopY = pinYPositions[currentPinIndex] + 20;
    if (tipTopY > 136) tipTopY = 136; // don't go below rest
  }

  // Vertical shaft of the tip
  drawRectangle(pickXPosition,     tipTopY, 4, 142 - tipTopY, COLOR_PICK);

  // Small L-hook notch (the elbow seen in the screenshot)
  drawRectangle(pickXPosition - 4, tipTopY, 4, 4, COLOR_PICK);
}

// ============================================================
// eraseDynamicElements  --  paints over moving parts only
// ============================================================
void eraseDynamicElements()
{
  int lineThickness = 3;
  int marginOffset  = 3;
  if (gameDifficulty == DIFF_MEDIUM) { lineThickness = 2; marginOffset = 2; }
  else if (gameDifficulty == DIFF_HARD) { lineThickness = 1; marginOffset = 1; }

  // Left wood patch (where the pick slides in)
  // drawRectangle(0, 130, 20, 24, COLOR_WOOD);

  // Horizontal keyway track
   drawRectangle(20, 130, 280, 24, COLOR_BLACK);

  // Each pin chamber (full height — springs are redrawn in drawDynamicElements)
  for (int i = 0; i < NUM_PINS; i++)
  {
    int cx = LOCK_BASE_X + 25 + (i * 32);
    drawRectangle(cx, LOCK_BASE_Y, CHAMBER_WIDTH, 90, COLOR_BLACK);
    // Restore shear line colour based on set state
    short int lineColor = pinSet[i] ? COLOR_GREEN : COLOR_RED;
    drawRectangle(cx, pinTargetY[i] - marginOffset, CHAMBER_WIDTH, lineThickness, lineColor);
  }
}

// ============================================================
// drawPadlockIcon  --  tiny padlock drawn with rectangles
//   x, y = top-left of the icon (icon is ~10 wide x 12 tall pixels)
// ============================================================
void drawPadlockIcon(int x, int y, short int bodyColor, short int shackleColor)
{
  // Shackle arch (inverted U)
  drawRectangle(x + 2, y,     2, 6, shackleColor); // left leg
  drawRectangle(x + 6, y,     2, 6, shackleColor); // right leg
  drawRectangle(x + 2, y,     6, 2, shackleColor); // top bar

  // Body
  drawRectangle(x,     y + 5, 10, 7, bodyColor);

  // Keyhole dot
  drawRectangle(x + 4, y + 7,  2, 3, COLOR_BLACK);
}

// ============================================================
// drawRotaryBar  --  tension bar + TENSION label + padlock icons
//                    + control hint at the very bottom
// ============================================================
void drawRotaryBar()
{
  // ---- TENSION label (character buffer) ----
  writeString(2, 52, "TENSION");

  // ---- Padlock icons showing sequence progress ----
  // Spacing: 5 icons across, starting at x=90, y=200
  int iconStartX = 90;
  int iconY      = 203;
  int iconSpacing = 30;

  for (int i = 0; i < NUM_PINS; i++)
  {
    int ix = iconStartX + (i * iconSpacing);

    if (pinSet[i])
    {
      // Green padlock = this pin is locked in
      drawPadlockIcon(ix, iconY, COLOR_GREEN, COLOR_GREEN);
    }
    else if (i == currentPinIndex)
    {
      // Gold/yellow = currently selected pin
      drawPadlockIcon(ix, iconY, COLOR_GOLD, COLOR_SPRING);
    }
    else
    {
      // Dark gray = not yet picked
      drawPadlockIcon(ix, iconY, 0x4208, 0x4208);
    }
  }

  // ---- Tension bar ----
  int barX = 20;
  int barY = 218;
  int barW = 280;
  int barH = 5;

  // Gray background track
  drawRectangle(barX, barY, barW, barH, 0xAD55);

  int rotary_difference;
  if (rotary_counter > target_rotary_end)
  {
    rotary_difference = rotary_counter - target_rotary_end;
    rotary_in_range   = false;
  }
  else if (rotary_counter < target_rotary_start)
  {
    rotary_difference = target_rotary_start - rotary_counter;
    rotary_in_range   = false;
  }
  else
  {
    rotary_difference = 0;
    rotary_in_range   = true;
  }

  int drawnBarWidth = barW - (rotary_difference * barW) / 255;
  short int bar_color = rotary_in_range ? COLOR_GREEN : COLOR_RED;

  if (drawnBarWidth > 0)
    drawRectangle(barX, barY, drawnBarWidth, barH, bar_color);

  // White indicator dot at the right edge of the drawn bar
  if (drawnBarWidth > 2)
    drawRectangle(barX + drawnBarWidth - 2, barY, 3, barH, 0xFFFF);

  // ---- Control hint (character buffer, bottom row) ----
  writeString(2, 58, "W:LIFT  A D:MOVE  C X:TURN");
}

// ============================================================
// readPS2
// ============================================================
int readPS2(char *byte)
{
  volatile int *ps2Ptr = (int *)PS2_BASE;
  int ps2Data = *ps2Ptr;

  if (ps2Data & 0x8000)
  {
    *byte = ps2Data & 0xFF;
    return 1;
  }
  return 0;
}

// ============================================================
// readKeys / waitForRelease
// ============================================================
int readKeys()
{
  volatile int *keyPtr = (int *)KEY_BASE;
  return *keyPtr;
}

void waitForRelease()
{
  while (readKeys() != 0) {}
}

// ============================================================
// wait_for_vsync
// ============================================================
void wait_for_vsync()
{
  volatile int *pixel_ctrl_ptr = (int *)0xFF203020;
  register int status;

  *pixel_ctrl_ptr = 1;
  status = *(pixel_ctrl_ptr + 3);
  while ((status & 0x01) != 0)
    status = *(pixel_ctrl_ptr + 3);
}

// ============================================================
// Audio — blocking start sound
// ============================================================
void playStartSound()
{
  volatile int *audioPtr = (int *)AUDIO_BASE;
  int sampleRate    = 8000;
  int freq          = 1760;
  int halfPeriod    = sampleRate / freq / 2;
  int volume        = 0x00FFFFFF;
  int durationSamples = sampleRate / 4;
  int currentSample = 0;
  int waveCounter   = 0;
  int currentAmplitude = volume;

  while (currentSample < durationSamples)
  {
    int fifoSpace     = *(audioPtr + 1);
    int leftFifoSpace  = (fifoSpace >> 24) & 0xFF;
    int rightFifoSpace = (fifoSpace >> 16) & 0xFF;

    if (leftFifoSpace > 0 && rightFifoSpace > 0)
    {
      *(audioPtr + 2) = currentAmplitude;
      *(audioPtr + 3) = currentAmplitude;
      currentSample++;
      waveCounter++;
      if (waveCounter >= halfPeriod)
      {
        currentAmplitude = -currentAmplitude;
        waveCounter = 0;
      }
    }
  }
}

void playSuccessSound()
{
  volatile int *audioPtr = (int *)AUDIO_BASE;
  int sampleRate = 8000;
  int volume     = 0x00FFFFFF;

  // First ding
  int freq1       = 2093;
  int halfPeriod1 = sampleRate / freq1 / 2;
  int duration1   = sampleRate / 10;
  int currentSample = 0, waveCounter = 0;
  int currentAmplitude = volume;

  while (currentSample < duration1)
  {
    int fifoSpace = *(audioPtr + 1);
    if (((fifoSpace >> 24) & 0xFF) > 0 && ((fifoSpace >> 16) & 0xFF) > 0)
    {
      *(audioPtr + 2) = currentAmplitude;
      *(audioPtr + 3) = currentAmplitude;
      currentSample++;
      if (++waveCounter >= halfPeriod1) { currentAmplitude = -currentAmplitude; waveCounter = 0; }
    }
  }

  // Silence
  currentSample = 0;
  while (currentSample < sampleRate / 20)
  {
    int fifoSpace = *(audioPtr + 1);
    if (((fifoSpace >> 24) & 0xFF) > 0 && ((fifoSpace >> 16) & 0xFF) > 0)
    { *(audioPtr + 2) = 0; *(audioPtr + 3) = 0; currentSample++; }
  }

  // Second higher ding
  int freq2       = 2637;
  int halfPeriod2 = sampleRate / freq2 / 2;
  int duration2   = (sampleRate * 15) / 100;
  currentSample = 0; waveCounter = 0; currentAmplitude = volume;

  while (currentSample < duration2)
  {
    int fifoSpace = *(audioPtr + 1);
    if (((fifoSpace >> 24) & 0xFF) > 0 && ((fifoSpace >> 16) & 0xFF) > 0)
    {
      *(audioPtr + 2) = currentAmplitude;
      *(audioPtr + 3) = currentAmplitude;
      currentSample++;
      if (++waveCounter >= halfPeriod2) { currentAmplitude = -currentAmplitude; waveCounter = 0; }
    }
  }
}

void playFailSound()
{
  volatile int *audioPtr = (int *)AUDIO_BASE;
  int sampleRate = 8000;
  int volume     = 0x00FFFFFF;
  int freq       = 150;
  int halfPeriod = sampleRate / freq / 2;
  int duration   = sampleRate / 3;
  int currentSample = 0, waveCounter = 0;
  int currentAmplitude = volume;

  while (currentSample < duration)
  {
    int fifoSpace = *(audioPtr + 1);
    if (((fifoSpace >> 24) & 0xFF) > 0 && ((fifoSpace >> 16) & 0xFF) > 0)
    {
      *(audioPtr + 2) = currentAmplitude;
      *(audioPtr + 3) = currentAmplitude;
      currentSample++;
      if (++waveCounter >= halfPeriod) { currentAmplitude = -currentAmplitude; waveCounter = 0; }
    }
  }
}

// ============================================================
// Switch / LED helpers
// ============================================================
int readSwitches()
{
  volatile int *sw = (int *)SWITCH_BASE;
  return (*sw) & 0x1F;
}

void updateLEDs(int ledToLight)
{
  volatile int *led = (int *)LED_BASE;
  *led = ledToLight;
}

void matchPins()
{
  int currentSwitches = readSwitches();
  matchedPins = 0;
  for (int pin = 0; pin < NUM_PINS; pin++)
  {
    int switchToggled = (currentSwitches >> pin) & 1;
    int patternBit    = (targetPattern   >> pin) & 1;
    if (switchToggled == patternBit)
      matchedPins |= (1 << pin);
  }
}

// ============================================================
// Timer / interrupt functions
// ============================================================
void set_itimer(void)
{
  volatile int *timer_ptr = (int *)TIMER_BASE;
  int counterValue = 100000000; // 1 second at 100 MHz
  *timer_ptr = 0;
  *(timer_ptr + 0x2) = counterValue & 0xFFFF;
  *(timer_ptr + 0x3) = (counterValue >> 16) & 0xFFFF;
  *(timer_ptr + 1)   = 0x7; // START + CONT + ITO
}

void enable_interrupts(void)
{
  JP1_DIR  = 0x00000000;
  JP1_EDGE = 0xFFFFFFFF;
  JP1_IE   = 0x00000001;

  int mstatus_value = 0b1000;
  __asm__ volatile("csrc mstatus, %0" ::"r"(mstatus_value));

  int mtvec_value = (int)&handler;
  __asm__ volatile("csrw mtvec, %0" ::"r"(mtvec_value));

  int mie_value;
  __asm__ volatile("csrr %0, mie" : "=r"(mie_value));
  __asm__ volatile("csrc mie, %0" ::"r"(mie_value));
  mie_value = (1 << 27) | (1 << 16);
  __asm__ volatile("csrs mie, %0" ::"r"(mie_value));
  __asm__ volatile("csrs mstatus, %0" ::"r"(mstatus_value));
}

void handler(void)
{
  int mcause_value;
  __asm__ volatile("csrr %0, mcause" : "=r"(mcause_value));

  if (mcause_value == 0x80000010)
    itimer_ISR();
  else if (mcause_value == JP1_MCAUSE)
    rotary_ISR();
}

void itimer_ISR(void)
{
  volatile int *timer_ptr = (int *)TIMER_BASE;
  *timer_ptr = 0; // clear interrupt

  if (state == GAME_STATE && timerStarted == 1)
  {
    elapsedTime++;

    if (rotary_in_range)
    {
      rotary_counter--;
      if (rotary_counter < 0) rotary_counter = 255;
    }
  }
}

void rotary_ISR(void)
{
  unsigned int pins = JP1_DATA;
  unsigned int B    = (pins >> 1) & 1;

  if (B == 1)
  {
    rotary_counter++;
    if (rotary_counter > 255) rotary_counter = 0;
  }
  else
  {
    rotary_counter--;
    if (rotary_counter < 0) rotary_counter = 255;
  }

  *LEDR_ptr = rotary_counter;
  JP1_EDGE  = 0xFFFFFFFF;
}
